// simulateTraffic generates synthetic requests to produce metric data for demonstration
func simulateTraffic() {
	users := []struct {
		id      string
		role    string
		region  string
		version string
	}{
		{"user-001", "admin", "us-east-1", "v2.1.0"},
		{"user-002", "editor", "us-west-2", "v2.0.5"},
		{"user-003", "viewer", "eu-west-1", "v2.1.0"},
		{"user-004", "admin", "ap-southeast-1", "v1.9.8"},
		{"user-005", "editor", "us-east-1", "v2.1.0"},
		{"user-006", "viewer", "eu-central-1", "v2.0.5"},
		{"user-007", "viewer", "us-west-2", "v2.1.0"},
		{"user-008", "editor", "ap-northeast-1", "v2.0.5"},
		{"user-009", "admin", "eu-west-1", "v1.9.8"},
		{"user-010", "viewer", "us-east-1", "v2.1.0"},
	}

	endpoints := []string{"/api/data", "/api/users", "/api/orders", "/api/search"}
	methods := []string{"GET", "POST", "PUT", "DELETE"}

	// Wait for server to start
	time.Sleep(2 * time.Second)

	client := &http.Client{Timeout: 10 * time.Second}

	for {
		user := users[rand.Intn(len(users))]
		endpoint := endpoints[rand.Intn(len(endpoints))]
		method := methods[rand.Intn(len(methods))]

		req, err := http.NewRequest(method, "http://localhost:8080"+endpoint, nil)
		if err != nil {
			log.Printf("Error creating request: %v", err)
			continue
		}

		req.Header.Set("X-User-ID", user.id)
		req.Header.Set("X-User-Role", user.role)
		req.Header.Set("X-Region", user.region)
		req.Header.Set("X-Client-Version", user.version)

		resp, err := client.Do(req)
		if err != nil {
			log.Printf("Error making request: %v", err)
		} else {
			resp.Body.Close()
		}

		// Random interval between requests (50ms to 500ms)
		time.Sleep(time.Duration(50+rand.Intn(450)) * time.Millisecond)
	}
}